  1	import * as React from 'react';
  2	import { mapLimitsRequests } from '@odf/shared/charts';
  3	import { AreaChart } from '@odf/shared/dashboards/utilization-card/area-chart';
  4	import {
  5	  ColoredIconProps,
  6	  Humanize,
  7	  LIMIT_STATE,
  8	  PrometheusResponse,
  9	  PrometheusResult,
 10	  RedExclamationCircleIcon,
 11	  TopConsumerPopoverProps,
 12	  YellowExclamationTriangleIcon,
 13	} from '@openshift-console/dynamic-plugin-sdk';
 14	import { ByteDataTypes } from '@openshift-console/dynamic-plugin-sdk/lib/api/internal-types';
 15	import { t_global_color_status_danger_default as dangerColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 16	import { t_global_color_status_warning_default as warningColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_warning_default';
 17	import { ChartThemeColor, ChartLegend } from '@patternfly/react-charts/victory';
 18	import { useCustomTranslation } from '../../useCustomTranslationHook';
 19	
 20	enum AreaChartStatus {
 21	  ERROR = 'ERROR',
 22	  WARNING = 'WARNING',
 23	}
 24	
 25	const chartStatusColors = {
 26	  [AreaChartStatus.ERROR]: dangerColor.value,
 27	  [AreaChartStatus.WARNING]: warningColor.value,
 28	};
 29	
 30	export const trimSecondsXMutator = (x: number) => {
 31	  const d = new Date(x * 1000);
 32	  d.setSeconds(0, 0);
 33	  return d;
 34	};
 35	
 36	export const UtilizationItem: React.FC<UtilizationItemProps> = React.memo(
 37	  ({
 38	    TopConsumerPopover,
 39	    byteDataType,
 40	    error,
 41	    humanizeValue,
 42	    isLoading = false,
 43	    limit,
 44	    max = null,
 45	    query,
 46	    requested,
 47	    setLimitReqState,
 48	    title,
 49	    utilization,
 50	    chartType,
 51	    description,
 52	    hideCurrentHumanized,
 53	    hideHorizontalBorder,
 54	    disableGraphLink,
 55	    showLegend,
 56	    CustomUtilizationSummary,
 57	    formatDate,
 58	    showHumanizedInLegend,
 59	  }) => {
 60	    const { t } = useCustomTranslation();
 61	    const { data, chartStyle } = mapLimitsRequests({
 62	      utilization,
 63	      limit,
 64	      requested,
 65	      xMutator: trimSecondsXMutator,
 66	      t,
 67	      description: description,
 68	    });
 69	    const [utilizationData, limitData, requestedData] = data;
 70	    const current = utilizationData?.length
 71	      ? utilizationData[utilizationData.length - 1].y
 72	      : null;
 73	
 74	    let humanMax: string;
 75	    let humanAvailable: string;
 76	    if (current && max) {
 77	      humanMax = humanizeValue(max).string;
 78	      const percentage = (100 * current) / max;
 79	
 80	      if (percentage >= 90) {
 81	        chartStyle[0] = {
 82	          data: { fill: chartStatusColors[AreaChartStatus.ERROR] },
 83	        };
 84	      } else if (percentage >= 80) {
 85	        chartStyle[0] = {
 86	          data: { fill: chartStatusColors[AreaChartStatus.WARNING] },
 87	        };
 88	      }
 89	
 90	      humanAvailable = humanizeValue(max - current).string;
 91	    }
 92	    let humanizedLegend: JSX.Element;
 93	    if (!!showHumanizedInLegend && current)
 94	      humanizedLegend = (
 95	        <ChartLegend
 96	          themeColor={ChartThemeColor.purple}
 97	          data={[{ name: description + ' : ' + humanizeValue(current).string }]}
 98	        />
 99	      );
100	
101	    const chart = (
102	      <AreaChart
103	        ariaChartLinkLabel={t('View {{title}} metrics in query browser', {
104	          title,
105	        })}
106	        ariaChartTitle={title}
107	        data={data}
108	        loading={!error && isLoading}
109	        query={!disableGraphLink && query}
110	        // Todo(bipuladh): Make humanize type Humanize once unit.js is converted
111	        humanize={humanizeValue as Humanize}
112	        byteDataType={byteDataType}
113	        chartStyle={chartStyle}
114	        chartType={chartType}
115	        mainDataName="usage"
116	        showLegend={showLegend}
117	        formatDate={formatDate}
118	        legendComponent={humanizedLegend}
119	      />
120	    );
121	
122	    // Code below is used to render Consumer Popovers.
123	    let LimitIcon: React.ComponentType<ColoredIconProps>;
124	    let humanLimit: string;
125	    let limitState = LIMIT_STATE.OK;
126	    let requestedState = LIMIT_STATE.OK;
127	
128	    const latestLimit = limitData?.length
129	      ? limitData[limitData.length - 1].y
130	      : null;
131	    const latestRequested = requestedData?.length
132	      ? requestedData[requestedData.length - 1].y
133	      : null;
134	
135	    if (max) {
136	      if (latestLimit && latestRequested) {
137	        humanLimit = humanizeValue(latestLimit).string;
138	        const limitPercentage = (100 * latestLimit) / max;
139	        const reqPercentage = (100 * latestRequested) / max;
140	        if (limitPercentage > 100) {
141	          limitState = LIMIT_STATE.ERROR;
142	        } else if (limitPercentage >= 75) {
143	          limitState = LIMIT_STATE.WARN;
144	        }
145	        if (reqPercentage > 100) {
146	          requestedState = LIMIT_STATE.ERROR;
147	        } else if (reqPercentage >= 75) {
148	          requestedState = LIMIT_STATE.WARN;
149	        }
150	        if ([limitState, requestedState].includes(LIMIT_STATE.ERROR)) {
151	          LimitIcon = RedExclamationCircleIcon;
152	        } else if ([limitState, requestedState].includes(LIMIT_STATE.WARN)) {
153	          LimitIcon = YellowExclamationTriangleIcon;
154	        }
155	        setLimitReqState &&
156	          setLimitReqState({ limit: limitState, requested: requestedState });
157	      }
158	    }
159	
160	    const currentHumanized =
161	      !hideCurrentHumanized && current ? humanizeValue(current).string : null;
162	
163	    return (
164	      <div
165	        className="co-utilization-card__item-ceph"
166	        data-test-id="utilization-item"
167	      >
168	        <div className="co-utilization-card__item-description-ceph">
169	          <div className="co-utilization-card__item-section">
170	            <h4 className="pf-v6-c-title" style={{ marginRight: '20px' }}>
171	              {title}
172	            </h4>
173	            {error || (!isLoading && !utilizationData?.length) ? (
174	              <div className="text-secondary">{t('Not available')}</div>
175	            ) : (
176	              <div className="co-utilization-card__item-section-ceph">
177	                {LimitIcon && (
178	                  <LimitIcon className="co-utilization-card__item-icon" />
179	                )}
180	                {TopConsumerPopover ? (
181	                  <TopConsumerPopover
182	                    current={currentHumanized}
183	                    limit={
184	                      latestLimit ? humanizeValue(latestLimit).string : null
185	                    }
186	                    requested={
187	                      latestRequested
188	                        ? humanizeValue(latestRequested).string
189	                        : null
190	                    }
191	                    available={humanAvailable}
192	                    total={humanMax}
193	                    limitState={limitState}
194	                    requestedState={requestedState}
195	                  />
196	                ) : (
197	                  currentHumanized
198	                )}
199	              </div>
200	            )}
201	          </div>
202	          {!error && (humanAvailable || humanMax) && (
203	            <div className="co-utilization-card__item-section">
204	              <span
205	                className="co-utilization-card__item-text"
206	                data-test="utilization-card-item-text"
207	              >
208	                {humanLimit && (
209	                  <span>
210	                    {t(
211	                      '{{humanAvailable}} available of {{humanLimit}} total limit',
212	                      {
213	                        humanAvailable,
214	                        humanLimit,
215	                      }
216	                    )}
217	                  </span>
218	                )}
219	                {!humanLimit && humanMax && (
220	                  <span>
221	                    {t('{{humanAvailable}} available of {{humanMax}}', {
222	                      humanAvailable,
223	                      humanMax,
224	                    })}
225	                  </span>
226	                )}
227	                {!humanLimit && !humanMax && (
228	                  <span>
229	                    {t('{{humanAvailable}} available', {
230	                      humanAvailable,
231	                    })}
232	                  </span>
233	                )}
234	              </span>
235	            </div>
236	          )}
237	        </div>
238	        <div className="co-utilization-card__item-chart">{chart}</div>
239	
240	        {!!CustomUtilizationSummary && (
241	          <CustomUtilizationSummary
242	            currentHumanized={humanizeValue(current).string}
243	            utilizationData={utilization?.data?.result}
244	          />
245	        )}
246	        {!hideHorizontalBorder && (
247	          <hr style={{ border: '1px lightgray solid', margin: '0px' }} />
248	        )}
249	      </div>
250	    );
251	  }
252	);
253	
254	UtilizationItem.displayName = 'UtilizationItem';
255	
256	export type CustomUtilizationSummaryProps = {
257	  currentHumanized: string;
258	  utilizationData: PrometheusResult[];
259	};
260	
261	type UtilizationItemProps = {
262	  title: string;
263	  utilization?: PrometheusResponse;
264	  limit?: PrometheusResponse;
265	  requested?: PrometheusResponse;
266	  isLoading: boolean;
267	  // Todo(bipuladh): Make humanize type Humanize once unit.js is converted
268	  humanizeValue: Function;
269	  query: string | string[];
270	  error: boolean;
271	  max?: number;
272	  byteDataType?: ByteDataTypes;
273	  TopConsumerPopover?: React.ComponentType<TopConsumerPopoverProps>;
274	  setLimitReqState?: (state: {
275	    limit: LIMIT_STATE;
276	    requested: LIMIT_STATE;
277	  }) => void;
278	  chartType?: 'stacked-area' | 'grouped-line';
279	  description?: string | ((result: PrometheusResult, index: number) => string);
280	  hideCurrentHumanized?: boolean;
281	  disableGraphLink?: boolean;
282	  showLegend?: boolean;
283	  hideHorizontalBorder?: boolean;
284	  CustomUtilizationSummary?: React.FC<CustomUtilizationSummaryProps>;
285	  formatDate?: (date: Date, showSeconds?: boolean) => string;
286	  showHumanizedInLegend?: boolean;
287	};

